"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import {
    MessageCircle, X, Send, Minimize2, Headphones,
    Bot, User, ChevronRight, PhoneCall, Mail, Sparkles
} from "lucide-react";
import { useChatStore } from "@/store/chat";

// ── Bot knowledge base ─────────────────────────────────────────────────────
const quickReplies = [
    "Info paket wisata",
    "Cara booking tour",
    "Cek status booking",
    "Promo & diskon",
];

function getBotReply(text: string): string {
    const lower = text.toLowerCase();
    if (lower.includes("info paket") || lower.includes("paket wisata") || lower.includes("tour apa"))
        return "Kami punya ratusan paket wisata! 🌏\n\n🏝️ **Bali** — mulai Rp 3,2 Jt\n🌊 **Raja Ampat** — mulai Rp 8,5 Jt\n🦎 **Komodo** — mulai Rp 9,6 Jt\n🌋 **Bromo** — mulai Rp 1,8 Jt\n\nKunjungi halaman **Paket Wisata** untuk melihat semua pilihan!";
    if (lower.includes("cara booking") || lower.includes("book") || lower.includes("pesan"))
        return "Cara booking sangat mudah! 📋\n1. Pilih paket wisata\n2. Klik **Book Sekarang**\n3. Isi data pemesan\n4. Pilih metode pembayaran\n5. Konfirmasi & selesai ✅\n\nAda pertanyaan lain?";
    if (lower.includes("status booking") || lower.includes("cek booking"))
        return "Untuk cek status booking:\n📱 Login ke akun Anda\n📋 Buka menu **Riwayat Booking**\n\nAtau hubungi kami dengan nomor booking di +62 812-3456-7890 📞";
    if (lower.includes("promo") || lower.includes("diskon") || lower.includes("murah"))
        return "Ada promo spesial! 🎉\n\n🔥 **Bali** — diskon 30% s/d akhir bulan\n✨ **Raja Ampat** — cashback Rp 500rb\n🎁 **Early Bird** — hemat 20% untuk booking 30 hari sebelumnya\n\nHub. agen kami untuk info lebih lanjut!";
    if (lower.includes("bali"))
        return "Bali adalah destinasi favorit kami! 🌴\n\nPaket populer:\n• **Bali Complete Experience** — 7 hari\n• **Bali Honeymoon Bliss** — 5 hari\n• **Bali Family Adventure** — 6 hari\n\nMulai dari Rp 3,2 Jt/orang sudah termasuk hotel & transport!";
    if (lower.includes("harga") || lower.includes("biaya") || lower.includes("berapa"))
        return "Harga paket kami bervariasi 💰\n\n• Domestik: **Rp 1,8 Jt – 12 Jt**/orang\n• Internasional: **Rp 8 Jt – 35 Jt**/orang\n\nSudah termasuk hotel, transport, & guide lokal! Mau lihat detail paket tertentu?";
    if (lower.includes("hotel") || lower.includes("menginap") || lower.includes("akomodasi"))
        return "Semua paket kami sudah termasuk akomodasi! 🏨\n\nKami bekerja sama dengan hotel bintang 3–5. Anda bisa upgrade kamar saat booking sesuai kebutuhan.";
    if (lower.includes("visa") || lower.includes("dokumen") || lower.includes("paspor"))
        return "Untuk paket internasional, kami membantu pengurusan visa! 📄\n\nDokumen yang biasanya diperlukan:\n• Paspor (min. 6 bulan berlaku)\n• Foto 4x6\n• Bukti keuangan\n\nTim kami akan memandu Anda step by step!";
    if (lower.includes("hubungi") || lower.includes("kontak") || lower.includes("telepon") || lower.includes("whatsapp"))
        return "Kontak Tim Senja Wisata 📞\n\n• WhatsApp: **+62 812-3456-7890**\n• Email: **info@senjawisata.com**\n• Jam: Senin–Jumat 08.00–17.00 WIB\n\nAtau klik **Hubungi Admin** di bawah untuk chat langsung! 👇";
    return "Terima kasih sudah menghubungi **Senja Wisata**! 😊\n\nSaya belum bisa menemukan jawaban yang tepat untuk pertanyaan Anda. Klik **Hubungi Admin** agar tim support kami yang berpengalaman bisa membantu Anda secara langsung!";
}

// ── Markdown-like bold renderer ────────────────────────────────────────────
function renderText(text: string) {
    return text.split("\n").map((line, i, arr) => {
        const parts = line.split(/\*\*(.*?)\*\*/g);
        return (
            <span key={i}>
                {parts.map((part, j) =>
                    j % 2 === 1 ? <strong key={j}>{part}</strong> : part
                )}
                {i < arr.length - 1 && <br />}
            </span>
        );
    });
}

// ── Main Component ─────────────────────────────────────────────────────────
export default function LiveChatWidget() {
    const [open, setOpen] = useState(false);
    const [minimized, setMinimized] = useState(false);
    const [input, setInput] = useState("");
    const [typing, setTyping] = useState(false);
    const [sessionId, setSessionId] = useState<string | null>(null);
    const [visitorName] = useState("Tamu");
    const [showHandoff, setShowHandoff] = useState(false);
    const [unread, setUnread] = useState(0);
    const [lastSeenCount, setLastSeenCount] = useState(0);

    const inputRef = useRef<HTMLInputElement>(null);
    const bottomRef = useRef<HTMLDivElement>(null);

    const {
        initSession,
        sendUserMessage,
        addBotMessage,
        requestAdmin,
        getSession,
        sessions,
    } = useChatStore();

    // Init session on mount
    useEffect(() => {
        const existingSession = sessions.find(
            (s) => s.status !== "closed" && s.visitorName === visitorName
        );
        if (existingSession) {
            setSessionId(existingSession.id);
        } else {
            const id = initSession(visitorName);
            setSessionId(id);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const session = sessionId ? getSession(sessionId) : undefined;
    const messages = session?.messages ?? [];
    const status = session?.status ?? "bot";

    // Track unread from admin/bot while closed
    useEffect(() => {
        if (!open) {
            const newCount = messages.length;
            setUnread(Math.max(0, newCount - lastSeenCount));
        } else {
            setLastSeenCount(messages.length);
            setUnread(0);
        }
    }, [messages.length, open, lastSeenCount]);

    // Auto scroll
    useEffect(() => {
        if (open && !minimized) {
            bottomRef.current?.scrollIntoView({ behavior: "smooth" });
        }
    }, [messages, open, minimized, typing]);

    // Focus input when opened
    useEffect(() => {
        if (open && !minimized) {
            setTimeout(() => inputRef.current?.focus(), 150);
        }
    }, [open, minimized]);

    // Show handoff button after 2+ user messages in bot mode
    const userMessageCount = messages.filter((m) => m.from === "user").length;
    useEffect(() => {
        if (userMessageCount >= 2 && status === "bot") {
            setShowHandoff(true);
        }
    }, [userMessageCount, status]);

    // Poll for admin replies (since we're using localStorage-based store)
    useEffect(() => {
        if (!sessionId) return;
        const interval = setInterval(() => {
            // Force re-render to pick up admin replies
            useChatStore.getState().getSession(sessionId);
        }, 2000);
        return () => clearInterval(interval);
    }, [sessionId]);

    const handleSend = useCallback(
        (text: string) => {
            if (!text.trim() || !sessionId) return;
            sendUserMessage(sessionId, text.trim());
            setInput("");

            // Bot only replies if status is "bot"
            if (status === "bot") {
                setTyping(true);
                const delay = 1000 + Math.random() * 800;
                setTimeout(() => {
                    const reply = getBotReply(text);
                    addBotMessage(sessionId, reply);
                    setTyping(false);
                }, delay);
            }
        },
        [sessionId, status, sendUserMessage, addBotMessage]
    );

    const handleHandoff = () => {
        if (!sessionId) return;
        requestAdmin(sessionId);
        setShowHandoff(false);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        handleSend(input);
    };

    // Status indicator
    const statusInfo = {
        bot: { label: "Online · Senja Assistant", color: "bg-emerald-400" },
        waiting: { label: "Menunggu admin...", color: "bg-amber-400 animate-pulse" },
        live: { label: "Admin Online · Live Support", color: "bg-emerald-400" },
        closed: { label: "Sesi selesai", color: "bg-slate-400" },
    }[status] ?? { label: "Online", color: "bg-emerald-400" };

    return (
        <>
            {/* ── Chat Panel ── */}
            {open && (
                <div
                    className={`fixed bottom-24 right-5 z-50 w-[340px] rounded-2xl shadow-2xl flex flex-col overflow-hidden
                        transition-all duration-300 ease-out
                        ${minimized ? "h-14" : "h-[530px]"}
                        animate-chat-slide-up`}
                    style={{ fontFamily: "inherit" }}
                >
                    {/* Header */}
                    <div
                        className="flex items-center gap-3 px-4 py-3 text-white flex-shrink-0"
                        style={{ background: "linear-gradient(135deg, #05073C 0%, #1A3C6E 100%)" }}
                    >
                        <div className="relative">
                            <div className="w-9 h-9 rounded-full bg-white/20 flex items-center justify-center">
                                {status === "live" ? <Headphones size={18} /> : <Bot size={18} />}
                            </div>
                            <span className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-[#05073C] ${statusInfo.color}`} />
                        </div>
                        <div className="flex-1 min-w-0">
                            <p className="font-bold text-sm leading-none">
                                {status === "live" ? "Tim Support Senja" : "Senja Assistant"}
                            </p>
                            <p className="text-white/70 text-xs mt-0.5 flex items-center gap-1">
                                <span className={`w-1.5 h-1.5 rounded-full inline-block ${statusInfo.color}`} />
                                {statusInfo.label}
                            </p>
                        </div>
                        <button
                            onClick={() => setMinimized(!minimized)}
                            className="p-1 hover:bg-white/10 rounded-lg transition-colors"
                            aria-label="Minimize"
                        >
                            <Minimize2 size={15} />
                        </button>
                        <button
                            onClick={() => setOpen(false)}
                            className="p-1 hover:bg-white/10 rounded-lg transition-colors"
                            aria-label="Close"
                        >
                            <X size={15} />
                        </button>
                    </div>

                    {!minimized && (
                        <>
                            {/* Messages */}
                            <div className="flex-1 overflow-y-auto bg-slate-50 px-3 py-3 space-y-3">
                                {messages.map((msg) => (
                                    <div
                                        key={msg.id}
                                        className={`flex gap-2 ${msg.from === "user" ? "flex-row-reverse" : ""}`}
                                    >
                                        {/* Avatar */}
                                        <div
                                            className={`w-7 h-7 rounded-full flex items-center justify-center flex-shrink-0 mt-0.5 text-white
                                            ${msg.from === "bot" ? "bg-[#05073C]"
                                                    : msg.from === "admin" ? "bg-emerald-600"
                                                        : "bg-rose-400"}`}
                                        >
                                            {msg.from === "bot" ? <Bot size={13} /> :
                                                msg.from === "admin" ? <Headphones size={13} /> :
                                                    <User size={13} />}
                                        </div>

                                        {/* Bubble */}
                                        <div className={`max-w-[78%] flex flex-col gap-0.5 ${msg.from === "user" ? "items-end" : "items-start"}`}>
                                            {msg.from === "admin" && (
                                                <span className="text-[10px] text-emerald-600 font-semibold px-1">
                                                    {msg.senderName || "Admin"}
                                                </span>
                                            )}
                                            <div
                                                className={`px-3 py-2 rounded-2xl text-sm leading-relaxed
                                                ${msg.from === "user"
                                                        ? "text-white rounded-tr-sm"
                                                        : msg.from === "admin"
                                                            ? "bg-emerald-50 border border-emerald-200 text-emerald-900 rounded-tl-sm"
                                                            : "bg-white shadow-sm text-slate-700 rounded-tl-sm"}`}
                                                style={msg.from === "user" ? {
                                                    background: "linear-gradient(135deg, #FC4C4D, #e03030)"
                                                } : {}}
                                            >
                                                {renderText(msg.text)}
                                            </div>
                                            <span className="text-[10px] text-slate-400 px-1">{msg.time}</span>
                                        </div>
                                    </div>
                                ))}

                                {/* Typing indicator */}
                                {typing && (
                                    <div className="flex gap-2 items-end">
                                        <div className="w-7 h-7 rounded-full bg-[#05073C] flex items-center justify-center flex-shrink-0">
                                            <Bot size={13} className="text-white" />
                                        </div>
                                        <div className="bg-white shadow-sm rounded-2xl rounded-tl-sm px-4 py-3 flex gap-1 items-center">
                                            <span className="w-2 h-2 bg-slate-300 rounded-full animate-bounce" style={{ animationDelay: "0ms" }} />
                                            <span className="w-2 h-2 bg-slate-300 rounded-full animate-bounce" style={{ animationDelay: "150ms" }} />
                                            <span className="w-2 h-2 bg-slate-300 rounded-full animate-bounce" style={{ animationDelay: "300ms" }} />
                                        </div>
                                    </div>
                                )}

                                {/* Waiting for admin */}
                                {status === "waiting" && (
                                    <div className="flex justify-center">
                                        <div className="bg-amber-50 border border-amber-200 rounded-xl px-4 py-3 text-center">
                                            <div className="w-8 h-8 mx-auto mb-2 rounded-full bg-amber-100 flex items-center justify-center">
                                                <Headphones size={16} className="text-amber-600" />
                                            </div>
                                            <p className="text-xs font-semibold text-amber-800">Menunggu Admin</p>
                                            <p className="text-xs text-amber-600 mt-0.5">Tim kami segera membalas...</p>
                                        </div>
                                    </div>
                                )}

                                <div ref={bottomRef} />
                            </div>

                            {/* Handoff Prompt (after 2+ user messages) */}
                            {showHandoff && status === "bot" && (
                                <div className="bg-blue/5 border-t border-blue/20 px-3 py-2.5 flex-shrink-0">
                                    <p className="text-xs text-slate-500 mb-1.5">
                                        💬 Belum terjawab? Hubungi tim support kami.
                                    </p>
                                    <button
                                        onClick={handleHandoff}
                                        className="flex items-center gap-2 text-xs font-semibold text-white px-3 py-1.5 rounded-full w-full justify-center transition-all hover:opacity-90 active:scale-95"
                                        style={{ background: "linear-gradient(135deg, #05073C, #1A3C6E)" }}
                                    >
                                        <Headphones size={13} />
                                        Hubungi Admin Langsung
                                        <ChevronRight size={13} />
                                    </button>
                                </div>
                            )}

                            {/* Quick Replies (only in bot mode) */}
                            {status === "bot" && (
                                <div className="bg-white border-t border-slate-100 px-3 pt-2 pb-1 flex gap-1.5 overflow-x-auto flex-shrink-0"
                                    style={{ scrollbarWidth: "none" }}>
                                    {quickReplies.map((q) => (
                                        <button
                                            key={q}
                                            onClick={() => handleSend(q)}
                                            className="text-xs whitespace-nowrap px-3 py-1.5 rounded-full border border-slate-200 hover:border-[#05073C] hover:text-[#05073C] text-slate-500 transition-colors flex-shrink-0"
                                        >
                                            {q}
                                        </button>
                                    ))}
                                </div>
                            )}

                            {/* Input */}
                            {status !== "closed" ? (
                                <form
                                    onSubmit={handleSubmit}
                                    className="bg-white border-t border-slate-100 px-3 py-3 flex gap-2 flex-shrink-0"
                                >
                                    <input
                                        ref={inputRef}
                                        type="text"
                                        value={input}
                                        onChange={(e) => setInput(e.target.value)}
                                        placeholder={
                                            status === "waiting" ? "Admin akan segera membalas..." :
                                                status === "live" ? "Ketik pesan untuk admin..." :
                                                    "Ketik pesan..."
                                        }
                                        disabled={status === "waiting"}
                                        className="flex-1 bg-slate-50 rounded-full px-4 py-2 text-sm outline-none border border-slate-200 focus:border-[#05073C] transition-colors disabled:opacity-60"
                                    />
                                    <button
                                        type="submit"
                                        disabled={!input.trim() || status === "waiting"}
                                        className="w-9 h-9 rounded-full flex items-center justify-center disabled:opacity-40 transition-all flex-shrink-0 hover:scale-105 active:scale-95"
                                        style={{ background: "linear-gradient(135deg, #FC4C4D, #e03030)" }}
                                    >
                                        <Send size={15} className="text-white" />
                                    </button>
                                </form>
                            ) : (
                                <div className="bg-slate-50 border-t border-slate-100 px-3 py-3 text-center flex-shrink-0">
                                    <p className="text-xs text-slate-400">Sesi chat selesai. Terima kasih! 😊</p>
                                </div>
                            )}

                            {/* Live mode — contact shortcut bar */}
                            {status === "live" && (
                                <div className="bg-white border-t border-slate-100 px-3 py-2 flex gap-2 flex-shrink-0">
                                    <a
                                        href="https://wa.me/6281234567890"
                                        target="_blank"
                                        rel="noreferrer"
                                        className="flex-1 flex items-center justify-center gap-1.5 text-xs font-semibold text-emerald-700 bg-emerald-50 hover:bg-emerald-100 py-1.5 rounded-full transition-colors"
                                    >
                                        <PhoneCall size={12} /> WhatsApp
                                    </a>
                                    <a
                                        href="mailto:info@senjawisata.com"
                                        className="flex-1 flex items-center justify-center gap-1.5 text-xs font-semibold text-blue-700 bg-blue/10 hover:bg-blue/20 py-1.5 rounded-full transition-colors"
                                    >
                                        <Mail size={12} /> Email
                                    </a>
                                </div>
                            )}

                            {/* Footer brand */}
                            <div className="bg-white px-4 py-1.5 flex items-center justify-center gap-1 border-t border-slate-50">
                                <Sparkles size={10} className="text-slate-300" />
                                <span className="text-[10px] text-slate-300">Powered by Senja Wisata</span>
                            </div>
                        </>
                    )}
                </div>
            )}

            {/* ── FAB Button ── */}
            <button
                onClick={() => { setOpen((o) => !o); setMinimized(false); }}
                className="fixed bottom-5 right-5 z-50 w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-all duration-300 hover:scale-110 active:scale-95"
                style={{
                    background: open
                        ? "#374151"
                        : "linear-gradient(135deg, #05073C 0%, #FC4C4D 100%)"
                }}
                aria-label="Live Chat"
            >
                {/* Pulse ring */}
                {!open && (
                    <span className="absolute inset-0 rounded-full animate-ping opacity-30"
                        style={{ background: "linear-gradient(135deg, #05073C, #FC4C4D)" }} />
                )}
                <div className="relative">
                    {open ? <X size={22} className="text-white" /> : <MessageCircle size={22} className="text-white" />}
                    {!open && unread > 0 && (
                        <span className="absolute -top-2.5 -right-2.5 w-5 h-5 bg-emerald-400 rounded-full flex items-center justify-center text-[10px] font-bold text-white border-2 border-white animate-bounce">
                            {unread > 9 ? "9+" : unread}
                        </span>
                    )}
                </div>
            </button>
        </>
    );
}
